<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>2048</title>
    <style>
        :root {
            --bg-color: #1e1e1e;
            --board-bg: #3a3a3a;
            --cell-bg: #555;
            --text-color: #f9f6f2;
            --tile-2: #eee4da;
            --tile-4: #ede0c8;
            --tile-8: #f2b179;
            --tile-16: #f59563;
            --tile-32: #f67c5f;
            --tile-64: #f65e3b;
            --tile-128: #edcf72;
            --tile-256: #edcc61;
            --tile-512: #edc850;
            --tile-1024: #edc53f;
            --tile-2048: #edc22e;
        }

        body {
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
            margin: 0;
        }

        .container {
            text-align: center;
            width: 320px;
        }

        h1 {
            font-size: 48px;
            margin: 0;
        }

        #score-container {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 20px;
        }

        .score-box {
            background-color: var(--board-bg);
            padding: 5px 15px;
            border-radius: 3px;
            font-weight: bold;
        }

        #board {
            display: grid;
            grid-template-columns: repeat(4, 70px);
            grid-template-rows: repeat(4, 70px);
            gap: 10px;
            background-color: var(--board-bg);
            padding: 10px;
            border-radius: 5px;
            margin-bottom: 20px;
        }

        .cell {
            width: 70px;
            height: 70px;
            background-color: var(--cell-bg);
            display: flex;
            justify-content: center;
            align-items: center;
            font-size: 32px;
            font-weight: bold;
            border-radius: 3px;
            color: #1a1a1a; /* Dark text for contrast on light tiles */
        }

        .cell[data-val="0"] {
            background-color: var(--cell-bg);
            color: transparent;
        }

        button {
            padding: 10px 20px;
            font-size: 16px;
            cursor: pointer;
            background-color: #555;
            color: white;
            border: none;
            border-radius: 3px;
        }

        button:hover {
            background-color: #777;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>2048</h1>
        <div id="score-container">
            <div class="score-box">Score: <span id="score-val">0</span></div>
            <button id="reset">New Game</button>
        </div>
        <div id="board"></div>
    </div>

    <script>
        // Game State
        const SIZE = 4;
        let board = [];
        let scoreVal = 0;

        // DOM Elements
        const boardEl = document.getElementById('board');
        const scoreEl = document.getElementById('score-val');

        // Initialize Board (Empty)
        function initBoard() {
            return Array(SIZE).fill().map(() => Array(SIZE).fill(0));
        }

        // Render Board to DOM
        function render() {
            boardEl.innerHTML = '';
            for(let r=0; r<SIZE; r++) {
                for(let c=0; c<SIZE; c++) {
                    const cell = document.createElement('div');
                    cell.className = 'cell';
                    const val = board[r][c];
                    cell.setAttribute('data-val', val);
                    if(val > 0) {
                        cell.textContent = val;
                        // Set color based on value
                        let colorVar = `--tile-${val}`;
                        if(!getComputedStyle(document.documentElement).getPropertyValue(colorVar)) {
                            // Fallback for high numbers or undefined
                            colorVar = '--tile-2048'; 
                        }
                        cell.style.backgroundColor = getComputedStyle(document.documentElement).getPropertyValue(colorVar) || '#edc22e';
                    } else {
                        cell.textContent = '';
                    }
                    boardEl.appendChild(cell);
                }
            }
            scoreEl.textContent = scoreVal;
        }

        // Add Random Tile (2 or 4)
        function spawnTile() {
            const emptyCells = [];
            for(let r=0; r<SIZE; r++) {
                for(let c=0; c<SIZE; c++) {
                    if(board[r][c] === 0) emptyCells.push({r, c});
                }
            }
            if(emptyCells.length > 0) {
                const cell = emptyCells[Math.floor(Math.random() * emptyCells.length)];
                board[cell.r][cell.c] = Math.random() < 0.9 ? 2 : 4;
            }
        }

        // Process a single line (slide and merge left logic)
        function processLine(line) {
            let filtered = line.filter(x => x !== 0);
            for(let i=0; i<filtered.length - 1; i++) {
                if(filtered[i] === filtered[i+1]) {
                    filtered[i] *= 2;
                    scoreVal += filtered[i];
                    filtered[i+1] = 0; // Mark as merged/removed
                    i++; // Skip next element
                }
            }
            let result = filtered.filter(x => x !== 0);
            while(result.length < SIZE) {
                result.push(0);
            }
            return result;
        }

        // Helper: Transpose Matrix
        function transpose(matrix) {
            return matrix[0].map((_, colIndex) => matrix.map(row => row[colIndex]));
        }

        // Move Logic (Corrected to avoid mutation before check)
        function moveCorrect(dir) {
            let tempBoard = JSON.parse(JSON.stringify(board)); // Deep copy for calculation
            let changed = false;

            if (dir === 'left') {
                for(let r=0; r<SIZE; r++) {
                    const newRow = processLine(tempBoard[r]);
                    if(JSON.stringify(newRow) !== JSON.stringify(tempBoard[r])) {
                        tempBoard[r] = newRow;
                        changed = true;
                    }
                }
            } else if (dir === 'right') {
                for(let r=0; r<SIZE; r++) {
                    const reversedRow = [...tempBoard[r]].reverse();
                    const processedRow = processLine(reversedRow);
                    const newRow = processedRow.reverse();
                    if(JSON.stringify(newRow) !== JSON.stringify(tempBoard[r])) {
                        tempBoard[r] = newRow;
                        changed = true;
                    }
                }
            } else if (dir === 'up') {
                let tBoard = transpose(tempBoard);
                for(let r=0; r<SIZE; r++) {
                    const newRow = processLine(tBoard[r]);
                    if(JSON.stringify(newRow) !== JSON.stringify(tBoard[r])) {
                        tBoard[r] = newRow;
                        changed = true;
                    }
                }
                tempBoard = transpose(tBoard);
            } else if (dir === 'down') {
                let tBoard = transpose(tempBoard);
                for(let r=0; r<SIZE; r++) {
                    const reversedRow = [...tBoard[r]].reverse();
                    const processedRow = processLine(reversedRow);
                    const newRow = processedRow.reverse();
                    if(JSON.stringify(newRow) !== JSON.stringify(tBoard[r])) {
                        tBoard[r] = newRow;
                        changed = true;
                    }
                }
                tempBoard = transpose(tBoard);
            }

            if (changed) {
                board = tempBoard;
                spawnTile();
                render();
            } else {
                // No change, do nothing
            }

            return changed;
        }

        // API Implementation
        window.game = {
            get size() { return SIZE; },

            reset: function() {
                board = initBoard();
                scoreVal = 0;
                spawnTile();
                spawnTile();
                render();
            },

            move: function(dir) {
                // Normalize direction string
                const validDirs = ['left', 'right', 'up', 'down'];
                if(!validDirs.includes(dir)) return false;

                return moveCorrect(dir);
            },

            board: function() {
                // Return a copy to prevent external mutation affecting internal state directly
                return JSON.parse(JSON.stringify(board));
            },

            setBoard: function(arr) {
                if (arr && arr.length === SIZE && arr.every(row => row.length === SIZE)) {
                    board = arr;
                    render();
                } else {
                    console.error("Invalid board array");
                }
            },

            score: function() {
                return scoreVal;
            }
        };

        // Event Listeners
        document.addEventListener('keydown', (e) => {
            if(['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
                e.preventDefault(); // Prevent scrolling
                window.game.move(e.key);
            }
        });

        document.getElementById('reset').addEventListener('click', () => {
            window.game.reset();
        });

        // Start Game on Load
        window.game.reset();

    </script>
</body>
</html>
